import 'package:flutter/material.dart';
import 'package:task_manager_flutter/ui/widgets/generic_grid_screen.dart';
import 'field_config.dart';
import 'tab_config.dart';

class GenericDetailFormScreen<T> extends StatefulWidget {
  final T item;
  final List<TabConfig> tabConfigs;
  final String title;
  final Future<void> Function(Map<String, dynamic> formData) onSave;
  final VoidCallback onBack;

  const GenericDetailFormScreen({
    super.key,
    required this.item,
    required this.tabConfigs,
    required this.title,
    required this.onSave,
    required this.onBack,
  });

  @override
  State<GenericDetailFormScreen<T>> createState() =>
      _GenericDetailFormScreenState<T>();
}

class _GenericDetailFormScreenState<T>
    extends State<GenericDetailFormScreen<T>> with SingleTickerProviderStateMixin {
  final _formKey = GlobalKey<FormState>();
  late TabController _tabController;
  final Map<String, dynamic> _formData = {};

  @override
  void initState() {
    super.initState();
    _tabController = TabController(length: widget.tabConfigs.length, vsync: this);

    // Pré-popular dados se o item for um Map (ou tiver toJson)
    if (widget.item is Map) {
      _formData.addAll(widget.item as Map<String, dynamic>);
    } else if (widget.item is dynamic && widget.item.toJson != null) {
      _formData.addAll((widget.item as dynamic).toJson());
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(widget.title),
        leading: IconButton(
          icon: const Icon(Icons.arrow_back),
          onPressed: widget.onBack,
        ),
        bottom: TabBar(
          controller: _tabController,
          tabs: widget.tabConfigs
              .map((tab) => Tab(icon: Icon(tab.icon), text: tab.title))
              .toList(),
        ),
      ),
      body: TabBarView(
        controller: _tabController,
        children: widget.tabConfigs.map((tab) {
          if (tab.isGrid) {
            // Se for GRID -> usa GenericGridScreen
            return GenericGridScreen(
              apiEndpoint: "${tab.endpoint}/${_formData['id']}",
              title: tab.title,
            );
          } else {
            // Se for FORM -> monta formulário
            return Form(
              key: _formKey,
              child: ListView(
                padding: const EdgeInsets.all(16),
                children: tab.fields!
                    .map((field) => field.buildFormField(
                          _formData,
                          (val) => setState(() => _formData[field.fieldName] = val),
                        ))
                    .toList(),
              ),
            );
          }
        }).toList(),
      ),
      floatingActionButton: FloatingActionButton(
        onPressed: () async {
          if (_formKey.currentState?.validate() ?? false) {
            await widget.onSave(_formData);
          }
        },
        child: const Icon(Icons.save),
      ),
    );
  }
}
